/**
 * Initialize Envelope (TVPX__50)
 * Expected inbound shape from Router:
 * {
 *   ctx, tg: { chat_id, message_id, reply_to_message_id, text }, input
 * }
 */

function fnv1a(str) {
  let h = 0x811c9dc5;
  for (let i = 0; i < str.length; i++) {
    h ^= str.charCodeAt(i);
    h = (h >>> 0) * 0x01000193;
  }
  return (h >>> 0).toString(16);
}

const incoming = $json || {};
const now = new Date().toISOString();

const baseCtx = (incoming.ctx && typeof incoming.ctx === 'object') ? incoming.ctx : {};
const traceId = String(baseCtx.trace_id || '').trim() || `tvpx_${fnv1a(JSON.stringify(incoming).slice(0, 5000) + '::' + now)}`;

const tg = incoming.tg || incoming.message || {};

const ctx = {
  project_ns: 'TVPX',
  brand_name: 'The Velvet Paradox',
  trace_id: traceId,
  trigger_mode: 'telegram',
  route_mode: 'reply_action',
  received_at: now,
  telegram_chat_id: String(tg.chat_id || tg.chat?.id || '').trim() || null,
  fal_api_key: String(baseCtx.fal_api_key || incoming.fal_api_key || '').trim(),
  fal_endpoint_url: String(baseCtx.fal_endpoint_url || incoming.fal_endpoint_url || '').trim(),

  // defaults for series
  series_default_count: Number(baseCtx.series_default_count || incoming.series_default_count || 4),
  series_max_count: Number(baseCtx.series_max_count || incoming.series_max_count || 8)
};

const chatId = String(tg.chat_id || tg.chat?.id || '').trim();
const replyToId = String(tg.reply_to_message_id || tg.reply_to_message?.message_id || '').trim();
const text = String(tg.text || tg.caption || '').trim();

if (!chatId) throw new Error('TVPX__50: Missing tg.chat_id');
if (!replyToId) throw new Error('TVPX__50: Missing tg.reply_to_message_id (must be a reply to an image message)');

return [{
  json: {
    ctx,
    tg: {
      chat_id: chatId,
      reply_to_message_id: Number(replyToId),
      text
    },
    input: incoming.input || incoming
  }
}];

const j = $json || {};
const text = String(j.tg?.text || '').trim();
const isSlashCommand = /^\s*\/\w+/.test(text);

let actionType = 'series';
let seriesRequest = null;
let bwRequest = null;
let videoRequest = null;

const bwMatch = text.match(/^\s*\/bw\b\s*(.*)$/i);
const videoMatch = text.match(/^\s*\/video\b\s*(.*)$/i);
const seriesMatch = text.match(/^\s*\/series\b\s*(.*)$/i);

if (bwMatch) {
  actionType = 'bw';
  bwRequest = {
    mode: 'explicit',
    instruction: String(bwMatch[1] || '').trim() || 'Translate this still into a tactile monochrome photograph with tonal realism, natural texture, and real-world optical truth.'
  };
} else if (videoMatch) {
  actionType = 'video';
  videoRequest = {
    mode: 'explicit',
    instruction: String(videoMatch[1] || '').trim() || 'Prepare slow ceremonial motion that preserves the still as a real photographed moment with believable physics.'
  };
} else {
  let count = Number(j.ctx?.series_default_count || 4);
  let instruction = '';
  let mode = 'implicit';

  if (seriesMatch) {
    mode = 'explicit';
    const rest = String(seriesMatch[1] || '').trim();
    const leading = rest.match(/^(\d+)\s*(.*)$/);

    if (leading) {
      count = Number(leading[1]);
      instruction = String(leading[2] || '').trim();
    } else {
      instruction = rest;
    }
  } else if (!isSlashCommand && text.length >= 8) {
    instruction = text;
    mode = 'freeform';
  } else if (isSlashCommand) {
    throw new Error('TVPX__50: unsupported reply command. Use /series, /bw, /video, or a meaningful freeform series instruction.');
  } else {
    throw new Error('TVPX__50: reply is too short to treat as a series instruction. Use /series or a meaningful modifier.');
  }

  if (!Number.isFinite(count) || count < 1) count = Number(j.ctx?.series_default_count || 4);
  count = Math.min(Math.max(count, 1), Number(j.ctx?.series_max_count || 8));

  if (!instruction) {
    instruction = 'Preserve identity and symbolic logic; vary atmosphere, distance, and light pressure subtly.';
  }

  seriesRequest = {
    count,
    instruction,
    mode
  };
}

return [{
  json: {
    ...j,
    reply_action: {
      type: actionType
    },
    series_request: seriesRequest,
    bw_request: bwRequest,
    video_request: videoRequest
  }
}];

/**
 * Reattach Context After Reply Lookup
 */

const base = $items('Parse Series Command')[0].json;
const row = $input.all()[0]?.json || null;

if (!row || !String(row.asset_id || '').trim()) {
  throw new Error('TVPX__50: Could not find reply index record for this replied message. Ensure TVPX__40 or TVPX__41 registered it.');
}
if (row.is_active === false) {
  throw new Error('TVPX__50: reply index is inactive for this message.');
}

return [{
  json: {
    ctx: base.ctx,
    tg: base.tg,
    reply_action: base.reply_action,
    series_request: base.series_request,
    bw_request: base.bw_request,
    video_request: base.video_request,
    reply_index: row
  }
}];

/**
 * Assemble Parent Packet
 * Ensures we have parent asset + parent concept; builds a compact packet.
 */

const base = $items('Reattach After Reply Lookup')[0].json;
const ctx = base.ctx;

const parentAsset = $items('Get Parent Asset')[0]?.json;
const parentConcept = $items('Get Parent Concept')[0]?.json;

if (!parentAsset || !String(parentAsset.asset_id || '').trim()) throw new Error('TVPX__50: Parent asset not found.');
if (!parentConcept || !String(parentConcept.concept_id || '').trim()) throw new Error('TVPX__50: Parent concept not found.');

const dna = (() => {
  try { return JSON.parse(parentConcept.series_dna_json || '{}'); } catch { return {}; }
})();

return [{
  json: {
    ctx,
    tg: base.tg,
    reply_action: base.reply_action,
    series_request: base.series_request,
    bw_request: base.bw_request,
    video_request: base.video_request,
    reply_index: base.reply_index,
    parent: {
      asset: parentAsset,
      concept: parentConcept,
      series_dna: dna
    }
  }
}];

