function parseStrictJson(raw) {
  const source = typeof raw === 'string'
    ? raw
    : raw?.text ?? raw?.output ?? raw?.result ?? JSON.stringify(raw);

  const text = String(source || '').trim();
  if (!text) throw new Error('Parser: empty LLM output.');

  const candidates = [
    text,
    text.replace(/```json\s*/gi, '').replace(/```/g, '').trim()
  ];

  for (const candidate of candidates) {
    try {
      return JSON.parse(candidate);
    } catch {}
  }

  const stripped = candidates[1];
  const start = stripped.indexOf('{');
  const end = stripped.lastIndexOf('}');
  if (start >= 0 && end > start) {
    const slice = stripped.slice(start, end + 1)
      .replace(/[\u201C\u201D]/g, '"')
      .replace(/[\u2018\u2019]/g, "'")
      .replace(/,\s*}/g, '}')
      .replace(/,\s*]/g, ']');

    try {
      return JSON.parse(slice);
    } catch (err) {
      throw new Error(`Parser: invalid salvaged JSON. ${err.message}`);
    }
  }

  throw new Error('Parser: could not find a valid JSON object.');
}

const BASE_NODE = 'Assemble Parent Packet';
const OUT_KEY = 'series_plan';

const base = $items(BASE_NODE)[0]?.json;
if (!base) {
  throw new Error(`Parser: base node "${BASE_NODE}" returned no data.`);
}

const parsed = parseStrictJson($json);

// Per-output hardening
if (OUT_KEY === 'critic') {
  parsed.approve = Boolean(parsed.approve);
  for (const key of ['score', 'brand_fit', 'novelty', 'visual_viability']) {
    parsed[key] = Number(parsed[key] || 0);
  }
}

if (OUT_KEY === 'abstraction') {
  let a = Number(parsed.abstraction_target || 6.2);
  const min = Number(base.ctx?.target_abstraction_min || 5.8);
  const max = Number(base.ctx?.target_abstraction_max || 6.8);
  if (!Number.isFinite(a)) a = 6.2;
  a = Math.max(min, Math.min(max, a));
  parsed.abstraction_target = Math.round(a * 10) / 10;
}

if (OUT_KEY === 'render_spec') {
  parsed.image_size = String(parsed.image_size || base.ctx?.image_size || '1024x1280');
  parsed.provider_controls = (parsed.provider_controls && typeof parsed.provider_controls === 'object')
    ? parsed.provider_controls
    : {};
  parsed.provider_controls.quality = String(parsed.provider_controls.quality || base.ctx?.quality || 'high');
  parsed.provider_controls.background = String(parsed.provider_controls.background || base.ctx?.background || 'opaque');
  parsed.provider_controls.output_format = String(parsed.provider_controls.output_format || base.ctx?.output_format || 'png');
}

if (OUT_KEY === 'caption_pack') {
  parsed.hashtags = Array.isArray(parsed.hashtags) ? parsed.hashtags : [];
  parsed.keywords = Array.isArray(parsed.keywords) ? parsed.keywords : [];
}

if (OUT_KEY === 'series_plan') {
  parsed.variations = Array.isArray(parsed.variations) ? parsed.variations : [];
}

return [{
  json: {
    ...base,
    [OUT_KEY]: parsed
  }
}];

function fnv1a(str) {
  let h = 0x811c9dc5;
  for (let i = 0; i < str.length; i++) {
    h ^= str.charCodeAt(i);
    h = (h >>> 0) * 0x01000193;
  }
  return (h >>> 0).toString(16);
}

const j = $json || {};
const ctx = j.ctx || {};
const parentConcept = j.parent?.concept || {};
const parentAsset = j.parent?.asset || {};
const replyIndex = j.reply_index || {};
const plan = j.series_plan || {};

const rootId = String(parentConcept.root_concept_id || parentConcept.concept_id || '').trim();
const parentId = String(parentConcept.concept_id || '').trim();
const rootAssetId = String(parentAsset.root_asset_id || parentAsset.asset_id || '').trim();
const parentAssetId = String(parentAsset.asset_id || '').trim();
const familyId = String(parentAsset.asset_family_id || replyIndex.asset_family_id || ctx.asset_family_id || '').trim();

if (!parentId) throw new Error('TVPX__50: missing parent concept_id.');
if (!parentAssetId) throw new Error('TVPX__50: missing parent asset_id.');

const now = new Date().toISOString();
const variations = Array.isArray(plan.variations) ? plan.variations : [];

return variations.map((v) => {
  const delta = String(v.prompt_delta || v.variation_instruction || '').trim();
  const seed = `${ctx.trace_id}::${parentId}::${v.variation_index}::${delta}`;
  const childId = `tvpx_cp_${fnv1a(seed)}`;

  let seriesDNA = {};
  try {
    seriesDNA = JSON.parse(String(parentConcept.series_dna_json || '{}'));
  } catch {
    seriesDNA = {};
  }

  const seriesGroupId = String(
    plan.series_group_id ||
    seriesDNA.series_group_id ||
    `tvpx_series_${fnv1a(parentId + '::' + now)}`
  ).trim();

  const childSeriesDNA = {
    ...seriesDNA,
    series_group_id: seriesGroupId,
    variation_index: Number(v.variation_index || 0),
    prompt_delta: delta,
    palette_shift: String(v.palette_shift || '').trim(),
    atmosphere_shift: String(v.atmosphere_shift || '').trim(),
    intensity_change: String(v.intensity_change || '').trim()
  };

  const thesis = String(parentConcept.concept_thesis || '').trim();
  const variationInstruction = String(v.variation_instruction || '').trim();
  const childThesis = variationInstruction
    ? `${thesis} | Variation: ${variationInstruction}`
    : thesis;

  const childCtx = {
    ...ctx,
    ...(familyId ? { asset_family_id: familyId } : {})
  };

  return {
    json: {
      ctx: childCtx,
      child: {
        concept_id: childId,
        trace_id: ctx.trace_id,
        origin_type: 'telegram_series',
        source_id: String(parentConcept.source_id || '').trim(),
        parent_concept_id: parentId,
        root_concept_id: rootId,
        seed_fragment_ids_json: String(parentConcept.seed_fragment_ids_json || '[]'),
        concept_thesis: childThesis,
        symbolic_tension: String(parentConcept.symbolic_tension || '').trim(),
        material_anchor: String(parentConcept.material_anchor || '').trim(),
        spatial_directive: String(parentConcept.spatial_directive || '').trim(),
        palette_directive: String(parentConcept.palette_directive || '{}'),
        texture_directive: String(parentConcept.texture_directive || '{}'),
        abstraction_target: Number(parentConcept.abstraction_target || 6.2),
        series_dna_json: JSON.stringify(childSeriesDNA),
        prompt_guardrails_json: String(parentConcept.prompt_guardrails_json || '{}'),
        quality_score: Number(parentConcept.quality_score || 0),
        state: 'ready',
        lock_owner: '',
        lock_expires_at: null,
        used_count: 0,
        last_used_at: null,
        created_at: now,
        updated_at: now
      },
      lineage: {
        lineage_id: `tvpx_lin_${fnv1a(childId + '::' + parentId)}`,
        series_group_id: seriesGroupId,
        root_asset_id: rootAssetId,
        parent_asset_id: parentAssetId,
        child_asset_id: null,
        parent_concept_id: parentId,
        child_concept_id: childId,
        variation_index: Number(v.variation_index || 0),
        variation_instruction: variationInstruction,
        continuity_rules_json: JSON.stringify(plan.continuity_rules || {}),
        created_at: now
      }
    }
  };
});

const base = $items('Assemble Parent Packet')[0]?.json || {};
const rows = $input.all().map(i => i.json).filter(r => r && Object.keys(r).length);
const existing = rows.find(r => String(r.asset_id || '').trim()) || null;
return [{ json: { ...base, existing_bw_asset: existing } }];

const base = $items('Reattach B W Lookup')[0]?.json || {};
const existing = base.existing_bw_asset || {};
const binKeys = $binary ? Object.keys($binary) : [];
if (!binKeys.length) throw new Error('TVPX__50: no binary downloaded for existing B&W asset.');
const firstKey = binKeys[0];
return [{
  json: {
    ctx: base.ctx,
    concept_id: String(existing.concept_id || base.parent?.concept?.concept_id || '').trim(),
    asset_id: String(existing.asset_id || '').trim(),
    asset_family_id: String(existing.asset_family_id || base.parent?.asset?.asset_family_id || '').trim() || null
  },
  binary: {
    image: $binary[firstKey]
  }
}];

const base = $items('Prepare Existing B W Telegram Packet')[0]?.json || {};
const resp = $json || {};
const msgId = resp.message_id || resp.result?.message_id || resp.data?.message_id;
return [{ json: { ...base, telegram: { bw_message_id: msgId ? Number(msgId) : null } } }];

function fnv1a(str) {
  let h = 0x811c9dc5;
  for (let i = 0; i < str.length; i++) {
    h ^= str.charCodeAt(i);
    h = (h >>> 0) * 0x01000193;
  }
  return (h >>> 0).toString(16);
}

const j = $json || {};
const parentAsset = j.parent?.asset || {};
const parentConcept = j.parent?.concept || {};
const bwInstruction = String(j.bw_request?.instruction || '').trim();
const fallbackAssetId = `tvpx_as_${fnv1a(String(parentAsset.asset_id || parentConcept.concept_id || j.ctx?.trace_id || '') + '::bw')}`;
const assetId = String(parentAsset.asset_id || '').trim().replace(/_(color|bw)$/i, '_bw') || fallbackAssetId;

const prompt = [
  'Photoreal black and white fine-art photograph, real-life camera image, not CGI or illustration.',
  `Scene thesis: ${String(parentConcept.concept_thesis || '').trim()}.`,
  `Symbolic tension: ${String(parentConcept.symbolic_tension || '').trim()}.`,
  `Material anchor: ${String(parentConcept.material_anchor || '').trim()}.`,
  `Spatial directive: ${String(parentConcept.spatial_directive || '').trim()}.`,
  'Preserve staged inevitability, negative space as pressure, tactile material truth, and believable lens behavior.',
  'If a person is present, keep natural skin texture, realistic eyes, hands, posture, wardrobe, age detail, and unretouched human asymmetry.',
  'Use rich tonal separation, filmic shadow rolloff, real grain logic, and physically plausible monochrome light.',
  bwInstruction
].filter(Boolean).join(' ');

const negative = 'cgi, 3d render, illustration, painterly brushstrokes, cartoon stylization, plastic skin, waxy skin, smooth skin, airbrushed skin, beauty retouching, uncanny eyes, bad hands, extra fingers, duplicate limbs, deformed anatomy, fake grain, glossy synthetic surfaces, text, watermark, logo';

return [{
  json: {
    ctx: j.ctx,
    concept_id: String(parentConcept.concept_id || '').trim(),
    asset_id: assetId,
    asset_family_id: String(parentAsset.asset_family_id || j.reply_index?.asset_family_id || '').trim() || null,
    concept_row: parentConcept,
    render_variant: 'bw',
    prompt,
    negative_prompt: negative,
    provider_controls: {
      image_size: '1024x1280',
      background: 'opaque',
      quality: 'high',
      output_format: 'png'
    }
  }
}];

const render = $json || {};
const base = $items('Build B W Render Request')[0]?.json || {};
const imageUrl = String(render.image_url || '').trim();
if (!imageUrl) {
  throw new Error('TVPX__50: B&W render returned no image_url.');
}
return [{
  json: {
    ctx: base.ctx,
    concept_id: String(render.concept_id || base.concept_id || '').trim(),
    asset_id: String(base.asset_id || '').trim(),
    asset_family_id: String(base.asset_family_id || '').trim() || null,
    family: {
      bw: {
        image_url: imageUrl,
        provider_image_url: imageUrl,
        output_format: String(render.output_format || base.provider_controls?.output_format || 'png')
      }
    }
  }
}];

function fnv1a(str) {
  let h = 0x811c9dc5;
  for (let i = 0; i < str.length; i++) {
    h ^= str.charCodeAt(i);
    h = (h >>> 0) * 0x01000193;
  }
  return (h >>> 0).toString(16);
}

const base = $items('Assemble Parent Packet')[0]?.json || {};
const parentAsset = base.parent?.asset || {};
const parentConcept = base.parent?.concept || {};
const rows = $input.all().map(i => i.json).filter(r => r && Object.keys(r).length && String(r.asset_id || '').trim());
const priority = { prepared: 5, queued: 4, processing: 3, failed: 2, timed_out: 1, cancelled: 0 };
rows.sort((a, b) => (priority[String(b.state || '').trim().toLowerCase()] || -1) - (priority[String(a.state || '').trim().toLowerCase()] || -1));
const existing = rows[0] || null;
const state = String(existing?.state || '').trim().toLowerCase();
const shouldUpsert = !existing || ['failed', 'timed_out', 'cancelled'].includes(state);
const shouldPrepare = !existing || state === 'queued' || ['failed', 'timed_out', 'cancelled'].includes(state);
const stillUrl = String(parentAsset.drive_view_url || parentAsset.drive_download_url || parentAsset.provider_image_url || '').trim();
if (!stillUrl) {
  throw new Error('TVPX__50: parent asset has no still image URL for motion prep.');
}
const videoSeedId = String(existing?.video_seed_id || `tvpx_vid_${fnv1a(String(parentAsset.asset_id || parentConcept.concept_id || base.ctx?.trace_id || ''))}`);
let ackText = 'The Velvet Paradox — motion prep queued for this image.';
if (state === 'prepared') ackText = 'The Velvet Paradox — motion prep already exists for this image.';
else if (state === 'processing') ackText = 'The Velvet Paradox — motion prep is already in progress for this image.';
else if (state === 'queued') ackText = 'The Velvet Paradox — motion prep was already queued; refreshing the prep run now.';
else if (['failed', 'timed_out', 'cancelled'].includes(state)) ackText = 'The Velvet Paradox — motion prep was stale, so it has been re-queued.';
return [{
  json: {
    ...base,
    existing_video_seed: existing,
    video_plan: {
      state,
      should_upsert: shouldUpsert,
      should_prepare: shouldPrepare,
      ack_text: ackText,
      video_seed: {
        video_seed_id: videoSeedId,
        asset_id: String(parentAsset.asset_id || '').trim(),
        concept_id: String(parentConcept.concept_id || '').trim(),
        provider_target: 'fal_video',
        still_image_drive_url: stillUrl,
        motion_prompt: String(base.video_request?.instruction || '').trim(),
        camera_motion_profile: '',
        duration_hint: '5-7s',
        aspect_ratio: '4:5',
        state: 'queued',
        created_at: new Date().toISOString()
      }
    }
  }
}];

const j = $json || {};
const child = (j.child && typeof j.child === 'object') ? j.child : {};
const ctx = (j.ctx && typeof j.ctx === 'object') ? { ...j.ctx } : {};
const conceptId = String(child.concept_id || j.concept_id || '').trim();
if (!conceptId) {
  throw new Error('TVPX__50: series child concept_id missing before image generation dispatch.');
}
return [{
  json: {
    ...j,
    ctx,
    concept_id: conceptId,
    asset_family_id: String(ctx.asset_family_id || j.asset_family_id || '').trim() || null
  }
}];
